import time
import jwt


def generate_jwt(user_id, role, secret_key, expires_in=3600, algorithm="HS256"):
    now = int(time.time())
    payload = {
        "sub": str(user_id),
        "role": role,
        "iat": now,
        "exp": now + expires_in,
    }
    token = jwt.encode(payload, secret_key, algorithm=algorithm)
    return token


if __name__ == "__main__":
    secret = "your-secret-key"
    token = generate_jwt(user_id=123, role="admin", secret_key=secret)
